import GoogleMapReact from 'google-map-react';
import cls from './MapView.module.scss';
import { useState } from 'react';

import {
	setKey,

} from "react-geocode";
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faCircleDot, faLocationDot } from '@fortawesome/free-solid-svg-icons';
import { getDistanceBetweenPoints } from '../../../shared/utility';
import { isMobile } from 'react-device-detect';

const R = require('ramda');

const MapView = props => {
	const { pins = { lat: 0, lng: 0, address: 'Nowhere' }, mapkey = '', current } = props;
	const averageLng = (Math.max(...pins.map(pin => pin.lng)) + Math.min(...pins.map(pin => pin.lng))) / 2;
	const averageLat = (Math.max(...pins.map(pin => pin.lat)) + Math.min(...pins.map(pin => pin.lat))) / 2;
	const distance = pins.length > 1 ? Math.round(getDistanceBetweenPoints(pins[0].lat, pins[0].lng, pins[1].lat, pins[1].lng,) / 1000) : 15;
	const [zoomLevel,] = useState(distance);

	const MyMarker = ({ text, tooltip, type='source' }) => (
		<div className={cls.circle}>
			<span className={cls.circleText} title={tooltip}>
				<FontAwesomeIcon icon={type=== 'destination' ? faLocationDot: faCircleDot} style={{ color: 'red', width: '30px', height: '30px' }} />
				
			</span>

		</div>
	);
	const distanceToMouse = (pt, mp) => {
		if (pt && mp) {
			return Math.sqrt((pt.x - mp.x) * (pt.x - mp.x) + (pt.y - mp.y) * (pt.y - mp.y));
		}
	};
	return (
		<div style={{ height: '500px', width: '98%', margin: isMobile ? '0' : '20px' }}>

			<div style={{ marginTop: '20px', height:'inherit', width: 'inherit' }}>
				<GoogleMapReact
					onClick={ev => {
					}}
					bootstrapURLKeys={{
						key: mapkey,
						language: 'en',
						region: 'US',
					}}
					center={{ lat: +averageLat, lng: +averageLng }}
					defaultZoom={zoomLevel < 15 ? 12 : zoomLevel+2}
					distanceToMouse={distanceToMouse}
				>
					{pins.length > 0 && pins.map((pin, index) => <MyMarker key={index} lat={pin.lat} lng={pin.lng} text={pin.address} tooltip={pin.address} type={pin.type} />)}

				</GoogleMapReact>
				
			</div>
		</div >
	);
};

export default MapView;
